previewCss:
.darma-loader-darma-custom-463 {color: var(--loader-color, #0891b2);
  --loader-secondary-color: var(--loader-secondary-color, #22d3ee);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 50px;
   aspect-ratio: 1;
   display: flex;
   filter: drop-shadow(0px 0px 1px var(--loader-color, #0891b2));
   animation: darma-loader-darma-custom-463-l3 1s infinite alternate linear;
}
.darma-loader-darma-custom-463:before  {
  content: "";
   flex: 1;
   background: var(--loader-color, #0891b2);
   border-radius: 50%;
   -webkit-mask: radial-gradient(circle closest-side at 66% 40%,#0000 115%,currentColor 118%);
}
@keyframes darma-loader-darma-custom-463-l3  {
  100% {filter:drop-shadow(0px 0px 20px var(--loader-color, #0891b2))}
}

